import 'dotenv/config';
import express from 'express';
import { importWorkflowsHandler } from './admin/import-workflows.js';
import { businessAnalyzerHandler } from './ai-factory/business-analyzer.js';
import { employeeGeneratorHandler } from './ai-factory/employee-generator.js';
import { agentGeneratorHandler } from './ai-factory/agent-generator.js';
import { promptGeneratorHandler } from './ai-factory/prompt-generator.js';
import { knowledgeGeneratorHandler } from './ai-factory/knowledge-generator.js';
import { deploymentManagerHandler } from './ai-factory/deployment-manager.js';
import { workflowAnalyzerHandler } from './ai-factory/workflow-analyzer.js';
import { templateSearchHandler } from './ai-factory/template-search.js';
import { workflowGenerateHandler } from './ai-factory/workflow-generate.js';
import { aiProviderHealthHandler } from './ai-provider.js';
import { supabaseHealthHandler } from './supabase.js';
import { aiFactoryHealthHandler, promptEngineHealthHandler, workflowGeneratorHealthHandler, businessAnalyzerHealthHandler, employeeGeneratorHealthHandler, agentGeneratorHealthHandler, workflowAnalyzerHealthHandler, templateSearchHealthHandler } from './health.js';
import { activateN8nWorkflowHandler, deactivateN8nWorkflowHandler, deleteN8nWorkflowHandler, deployN8nWorkflowHandler, executeN8nWorkflowHandler, getN8nWorkflowHandler, n8nHealthHandler, syncN8nCredentialsHandler, updateN8nWorkflowHandler } from './n8n.js';
import { marketplacePublishHandler, marketplaceRecommendHandler } from './marketplace.js';
import { templateLibraryScanHandler, templateLibraryStatsHandler } from './template-library.js';
import { qaEngineHandler } from './qa-engine.js';
import { solutionArchitectHandler } from './solution-architect.js';
const app = express();
app.use(express.json());
app.post('/api/admin/import-workflows', importWorkflowsHandler);
app.post('/api/ai-factory/business-analyzer', businessAnalyzerHandler);
app.post('/api/ai-factory/employee-generator', employeeGeneratorHandler);
app.post('/api/ai-factory/agent-generator', agentGeneratorHandler);
app.post('/api/ai-factory/prompt-generator', promptGeneratorHandler);
app.post('/api/ai-factory/knowledge-generator', knowledgeGeneratorHandler);
app.post('/api/ai-factory/deploy', deploymentManagerHandler);
app.post('/api/workflow-analyzer', workflowAnalyzerHandler);
app.post('/api/template-search', templateSearchHandler);
app.post('/api/workflow-generate', workflowGenerateHandler);
app.post('/api/qa/evaluate', qaEngineHandler);
app.post('/api/solution-architect/design', solutionArchitectHandler);
app.post('/api/marketplace/publish', marketplacePublishHandler);
app.post('/api/marketplace/recommend', marketplaceRecommendHandler);
app.post('/api/template-library/scan', templateLibraryScanHandler);
app.get('/api/template-library/stats', templateLibraryStatsHandler);
app.get('/api/health', aiFactoryHealthHandler);
app.get('/api/health/ai-provider', aiProviderHealthHandler);
app.get('/api/health/supabase', supabaseHealthHandler);
app.get('/api/health/prompt-engine', promptEngineHealthHandler);
app.get('/api/health/workflow-generator', workflowGeneratorHealthHandler);
app.get('/api/health/business-analyzer', businessAnalyzerHealthHandler);
app.get('/api/health/employee-generator', employeeGeneratorHealthHandler);
app.get('/api/health/agent-generator', agentGeneratorHealthHandler);
app.get('/api/health/workflow-analyzer', workflowAnalyzerHealthHandler);
app.get('/api/health/template-search', templateSearchHealthHandler);
app.post('/api/n8n/deploy', deployN8nWorkflowHandler);
app.post('/api/n8n/update', updateN8nWorkflowHandler);
app.post('/api/n8n/activate', activateN8nWorkflowHandler);
app.post('/api/n8n/deactivate', deactivateN8nWorkflowHandler);
app.post('/api/n8n/execute', executeN8nWorkflowHandler);
app.delete('/api/n8n/workflow/:id', deleteN8nWorkflowHandler);
app.get('/api/n8n/workflow/:id', getN8nWorkflowHandler);
app.get('/api/n8n/health', n8nHealthHandler);
app.post('/api/n8n/credentials/sync', syncN8nCredentialsHandler);
const port = Number(process.env.PORT ?? 3000);
app.listen(port, () => {
    console.log(`Automation import server listening on port ${port}`);
});
